1	import * as fs from 'fs';
2	import * as path from 'path';
3	import * as os from 'os';
4	import Database from 'better-sqlite3';
5	import type { SessionProvider } from './types.js';
6	import type { ParsedSession, ParsedMessage, ToolCall } from '../types.js';
7	import { generateTitle, detectSessionCharacter } from '../parser/titles.js';
8	import { isVerbose } from './context.js';
9	
10	/**
11	 * Cursor IDE session provider.
12	 * Discovers and parses sessions from Cursor's SQLite databases.
13	 *
14	 * Cursor stores composer conversations in state.vscdb files (SQLite).
15	 * One DB can contain multiple sessions (composers), so discover() returns
16	 * virtual paths in the format `state.vscdb#<composerId>` — one per session.
17	 * This keeps the SessionProvider interface unchanged (1 path = 1 session).
18	 */
19	export class CursorProvider implements SessionProvider {
20	  getProviderName(): string {
21	    return 'cursor';
22	  }
23	
24	  /**
25	   * Discover Cursor composer sessions.
26	   * Returns virtual paths: `<dbPath>#<composerId>` — one per session.
27	   */
28	  async discover(options?: { projectFilter?: string }): Promise<string[]> {
29	    const cursorDataDir = getCursorDataDir();
30	    if (!cursorDataDir) {
31	      return [];
32	    }
33	
34	    const dbPaths: string[] = [];
35	
36	    // 1. Check workspace storage databases
37	    const workspaceStorageDir = path.join(cursorDataDir, 'workspaceStorage');
38	    if (fs.existsSync(workspaceStorageDir)) {
39	      const entries = fs.readdirSync(workspaceStorageDir);
40	      for (const entry of entries) {
41	        const wsDir = path.join(workspaceStorageDir, entry);
42	        if (!fs.statSync(wsDir).isDirectory()) continue;
43	
44	        const dbPath = path.join(wsDir, 'state.vscdb');
45	        if (!fs.existsSync(dbPath)) continue;
46	
47	        // Apply project filter if specified
48	        if (options?.projectFilter) {
49	          const projectPath = resolveWorkspacePath(wsDir);
50	          if (projectPath && !projectPath.toLowerCase().includes(options.projectFilter.toLowerCase())) {
51	            continue;
52	          }
53	        }
54	
55	        dbPaths.push(dbPath);
56	      }
57	    }
58	
59	    // 2. Check global storage database
60	    const globalDbPath = path.join(cursorDataDir, 'globalStorage', 'state.vscdb');
61	    if (fs.existsSync(globalDbPath)) {
62	      dbPaths.push(globalDbPath);
63	    }
64	
65	    // Expand each DB path into virtual paths — one per composer session
66	    const virtualPaths: string[] = [];
67	
68	    for (const dbPath of dbPaths) {
69	      const composerIds = getComposerIds(dbPath);
70	      for (const composerId of composerIds) {
71	        virtualPaths.push(`${dbPath}#${composerId}`);
72	      }
73	    }
74	
75	    return virtualPaths;
76	  }
77	
78	  /**
79	   * Parse a single Cursor session from a virtual path.
80	   * Virtual path format: `<dbPath>#<composerId>`
81	   */
82	  async parse(virtualPath: string): Promise<ParsedSession | null> {
83	    const hashIndex = virtualPath.lastIndexOf('#');
84	    if (hashIndex === -1) return null;
85	
86	    const dbPath = virtualPath.slice(0, hashIndex);
87	    const composerId = virtualPath.slice(hashIndex + 1);
88	    if (!composerId) return null;
89	
90	    return parseCursorSession(dbPath, composerId);
91	  }
92	}
93	
94	// ---------------------------------------------------------------------------
95	// Helper functions
96	// ---------------------------------------------------------------------------
97	
98	/**
99	 * Find Cursor's data directory based on the current platform.
100	 */
101	function getCursorDataDir(): string | null {
102	  const platform = process.platform;
103	  const home = os.homedir();
104	
105	  let dataDir: string;
106	  if (platform === 'darwin') {
107	    dataDir = path.join(home, 'Library', 'Application Support', 'Cursor', 'User');
108	  } else if (platform === 'linux') {
109	    dataDir = path.join(home, '.config', 'Cursor', 'User');
110	  } else if (platform === 'win32') {
111	    dataDir = path.join(process.env.APPDATA || path.join(home, 'AppData', 'Roaming'), 'Cursor', 'User');
112	  } else {
113	    return null;
114	  }
115	
116	  return fs.existsSync(dataDir) ? dataDir : null;
117	}
118	
119	/**
120	 * Resolve the project path from a workspace hash directory.
121	 * Reads workspace.json which contains the folder URI.
122	 */
123	function resolveWorkspacePath(wsDir: string): string | null {
124	  const workspaceJsonPath = path.join(wsDir, 'workspace.json');
125	  if (fs.existsSync(workspaceJsonPath)) {
126	    try {
127	      const data = JSON.parse(fs.readFileSync(workspaceJsonPath, 'utf-8'));
128	      if (data.folder) {
129	        // folder is a file:// URI like "file:///Users/name/projects/my-app"
130	        try {
131	          const url = new URL(data.folder);
132	          return decodeURIComponent(url.pathname);
133	        } catch {
134	          // Not a valid URL, try using it as-is
135	          return data.folder;
136	        }
137	      }
138	    } catch {
139	      // Ignore parse errors
140	    }
141	  }
142	  return null;
143	}
144	
145	/**
146	 * Extract the filesystem path from a VSCode URI object.
147	 *
148	 * Cursor stores code block file references as VSCode URI objects like:
149	 *   {"scheme":"file","path":"/abs/path.ts","_fsPath":"/abs/path.ts","fsPath":"/abs/path.ts"}
150	 *
151	 * Field presence varies across Cursor versions — prefer the most explicit field.
152	 */
153	function extractFilePath(uri: unknown): string {
154	  if (typeof uri === 'string') return uri;
155	  if (uri && typeof uri === 'object') {
156	    const obj = uri as Record<string, unknown>;
157	    // Prefer explicit fs path fields over the generic 'path' which could be URL-encoded
158	    if (typeof obj._fsPath === 'string' && obj._fsPath) return obj._fsPath;
159	    if (typeof obj.fsPath === 'string' && obj.fsPath) return obj.fsPath;
160	    if (typeof obj.path === 'string' && obj.path) return obj.path;
161	    // _formatted and external are file:// URLs — extract the path component
162	    for (const urlField of ['_formatted', 'external'] as const) {
163	      const val = obj[urlField];
164	      if (typeof val === 'string' && val.startsWith('file://')) {
165	        try {
166	          return decodeURIComponent(new URL(val).pathname);
167	        } catch {
168	          // Fall through to next field
169	        }
170	      }
171	    }
172	  }
173	  return '';
174	}
175	
176	/**
177	 * Extract plain text from a Lexical editor JSON structure.
178	 *
179	 * Cursor's composer uses the Lexical editor for user input. When a user message
180	 * is stored as `richText`, it's a Lexical JSON tree rather than plain text:
181	 *   {"root":{"children":[{"children":[{"text":"actual message"}],"type":"paragraph"}]}}
182	 *
183	 * We recursively collect all "text" leaf nodes and join them with newlines.
184	 * Returns null if the input is not valid Lexical JSON.
185	 */
186	function extractLexicalText(input: unknown): string | null {
187	  // Accept both pre-parsed objects and JSON strings
188	  let parsed: unknown = input;
189	  if (typeof input === 'string') {
190	    // Quick guard: Lexical JSON always starts with {"root"
191	    if (!input.startsWith('{"root"')) return null;
192	    try {
193	      parsed = JSON.parse(input);
194	    } catch {
195	      return null;
196	    }
197	  }
198	  if (!parsed || typeof parsed !== 'object') return null;
199	  const obj = parsed as Record<string, unknown>;
200	  if (!obj.root || typeof obj.root !== 'object') return null;
201	  const root = obj.root as Record<string, unknown>;
202	  if (!Array.isArray(root.children)) return null;
203	
204	  const text = collectLexicalText(root.children as Array<Record<string, unknown>>).trim();
205	  return text.length > 0 ? text : null;
206	}
207	
208	function collectLexicalText(nodes: Array<Record<string, unknown>>): string {
209	  const parts: string[] = [];
210	  for (const node of nodes) {
211	    if (typeof node.text === 'string' && node.text) {
212	      parts.push(node.text);
213	    }
214	    if (node.type === 'linebreak') {
215	      parts.push('\n');
216	    }
217	    if (Array.isArray(node.children)) {
218	      const childText = collectLexicalText(node.children as Array<Record<string, unknown>>);
219	      if (childText) {
220	        parts.push(childText);
221	        // Preserve paragraph boundaries for block-level nodes
222	        if (typeof node.type === 'string' && ['paragraph', 'heading', 'list-item', 'quote'].includes(node.type)) {
223	          parts.push('\n');
224	        }
225	      }
226	    }
227	  }
228	  return parts.join('');
229	}
230	
231	/**
232	 * Extract a project path from composerData by inspecting file paths in code blocks
233	 * and matching against relative file paths in relevantFiles.
234	 *
235	 * This is the fallback for sessions in the global DB where workspace.json is unavailable.
236	 * We find absolute paths in codeBlock URIs, then strip the relative portion to get the root.
237	 *
238	 * Example:
239	 *   codeBlock uri.path = "/Users/name/projects/crm/backend/auth.ts"
240	 *   relevantFile = "backend/auth.ts"
241	 *   → project root = "/Users/name/projects/crm"
242	 */
243	function extractProjectPathFromComposerData(composerData: Record<string, unknown>): string | null {
244	  const conversation = composerData.conversation;
245	  if (!Array.isArray(conversation)) return null;
246	  return extractProjectPathFromBubbles(conversation as Array<Record<string, unknown>>);
247	}
248	
249	/**
250	 * Extract a project path from raw bubble objects.
251	 *
252	 * Works the same way as extractProjectPathFromComposerData but operates on a
253	 * pre-loaded bubble array. Used for fullConversationHeadersOnly sessions where
254	 * codeBlocks live in individual bubbleId rows (not inline in composerData).
255	 */
256	function extractProjectPathFromBubbles(bubbles: Array<Record<string, unknown>>): string | null {
257	  for (const bubble of bubbles) {
258	    const codeBlocks = bubble.codeBlocks;
259	    const relevantFiles = bubble.relevantFiles;
260	
261	    if (Array.isArray(codeBlocks) && Array.isArray(relevantFiles) && relevantFiles.length > 0) {
262	      for (const block of codeBlocks as Array<Record<string, unknown>>) {
263	        const absPath = extractFilePath(block.uri);
264	        if (!absPath || !path.isAbsolute(absPath)) continue;
265	
266	        for (const rel of relevantFiles as string[]) {
267	          if (typeof rel !== 'string') continue;
268	          const normalRel = rel.replace(/\\/g, '/');
269	          const normalAbs = absPath.replace(/\\/g, '/');
270	          if (normalAbs.endsWith('/' + normalRel)) {
271	            return normalAbs.slice(0, normalAbs.length - normalRel.length - 1);
272	          }
273	        }
274	      }
275	    }
276	  }
277	
278	  return null;
279	}
280	
281	/**
282	 * Open the Cursor global DB regardless of which DB path was provided.
283	 * The global DB stores full composer conversation data in cursorDiskKV.
284	 * Returns null if the global DB doesn't exist or can't be opened.
285	 */
286	function openGlobalDb(anyDbPath: string): InstanceType<typeof Database> | null {
287	  const cursorDataDir = getCursorDataDir();
288	  if (!cursorDataDir) return null;
289	
290	  const globalDbPath = path.join(cursorDataDir, 'globalStorage', 'state.vscdb');
291	  // Avoid opening the same DB that was already opened by the caller
292	  if (!fs.existsSync(globalDbPath) || globalDbPath === anyDbPath) return null;
293	
294	  try {
295	    return new Database(globalDbPath, { readonly: true, fileMustExist: true });
296	  } catch {
297	    return null;
298	  }
299	}
300	
301	/**
302	 * Get all composer IDs from a Cursor database file.
303	 * Tries multiple storage strategies to find composer sessions.
304	 */
305	function getComposerIds(dbPath: string): string[] {
306	  let db: InstanceType<typeof Database> | null = null;
307	  try {
308	    db = new Database(dbPath, { readonly: true, fileMustExist: true });
309	
310	    const ids: string[] = [];
311	
312	    // Strategy 1: Check cursorDiskKV table for composerData entries (global DB)
313	    const hasCursorDiskKV = db.prepare(
314	      "SELECT name FROM sqlite_master WHERE type='table' AND name='cursorDiskKV'"
315	    ).get();
316	
317	    if (hasCursorDiskKV) {
318	      const rows = db.prepare(
319	        "SELECT key FROM cursorDiskKV WHERE key LIKE 'composerData:%'"
320	      ).all() as { key: string }[];
321	
322	      for (const row of rows) {
323	        const composerId = row.key.replace('composerData:', '');
324	        if (composerId) ids.push(composerId);
325	      }
326	    }
327	
328	    // Strategy 2: Check ItemTable for composer.composerData (workspace DBs)
329	    if (ids.length === 0) {
330	      const hasItemTable = db.prepare(
331	        "SELECT name FROM sqlite_master WHERE type='table' AND name='ItemTable'"
332	      ).get();
333	
334	      if (hasItemTable) {
335	        const row = db.prepare(
336	          "SELECT value FROM ItemTable WHERE key = 'composer.composerData'"
337	        ).get() as { value: string } | undefined;
338	
339	        if (row?.value) {
340	          try {
341	            const data = JSON.parse(row.value);
342	            const composers = data.allComposers || data.composers || [];
343	            for (const c of composers) {
344	              if (c.composerId) ids.push(c.composerId);
345	            }
346	          } catch {
347	            // Ignore parse errors
348	          }
349	        }
350	      }
351	    }
352	
353	    return ids;
354	  } catch {
355	    return [];
356	  } finally {
357	    db?.close();
358	  }
359	}
360	
361	/**
362	 * Parse a single Cursor composer session from a database.
363	 */
364	function parseCursorSession(dbPath: string, composerId: string): ParsedSession | null {
365	  let db: InstanceType<typeof Database> | null = null;
366	  try {
367	    db = new Database(dbPath, { readonly: true, fileMustExist: true });
368	
369	    let composerData: Record<string, unknown> | null = null;
370	
371	    // Try cursorDiskKV first (global DB)
372	    const hasCursorDiskKV = db.prepare(
373	      "SELECT name FROM sqlite_master WHERE type='table' AND name='cursorDiskKV'"
374	    ).get();
375	
376	    if (hasCursorDiskKV) {
377	      const row = db.prepare(
378	        "SELECT value FROM cursorDiskKV WHERE key = ?"
379	      ).get(`composerData:${composerId}`) as { value: string } | undefined;
380	
381	      if (row?.value) {
382	        try {
383	          composerData = JSON.parse(row.value) as Record<string, unknown>;
384	        } catch {
385	          console.warn(`[cursor] failed to parse cursorDiskKV composerData for composer ${composerId}`);
386	        }
387	      }
388	    }
389	
390	    // Fallback: try ItemTable composer.composerData
391	    if (!composerData) {
392	      const hasItemTable = db.prepare(
393	        "SELECT name FROM sqlite_master WHERE type='table' AND name='ItemTable'"
394	      ).get();
395	
396	      if (hasItemTable) {
397	        const row = db.prepare(
398	          "SELECT value FROM ItemTable WHERE key = 'composer.composerData'"
399	        ).get() as { value: string } | undefined;
400	
401	        if (row?.value) {
402	          try {
403	            const allData = JSON.parse(row.value) as Record<string, unknown>;
404	            const composers = (allData.allComposers || allData.composers || []) as Array<Record<string, unknown>>;
405	            composerData = composers.find((c) => c.composerId === composerId) || null;
406	          } catch {
407	            console.warn(`[cursor] failed to parse ItemTable composerData for composer ${composerId}`);
408	          }
409	        }
410	      }
411	    }
412	
413	    if (!composerData) return null;
414	
415	    // Extract messages from composer data.
416	    // Pass db handle for the fullConversationHeadersOnly format where
417	    // bubble content is stored in separate cursorDiskKV rows.
418	    // rawBubbles is retained for project path inference (extractProjectPathFromBubbles).
419	    let [messages, rawBubbles] = extractMessages(composerData, composerId, db);
420	
421	    // Workspace DBs only store composer metadata (composerId, name, timestamps) in ItemTable.
422	    // Full conversation data (with bubbles) lives in the global DB's cursorDiskKV table.
423	    // If we got no messages from the workspace DB, look up the composer in the global DB.
424	    if (messages.length === 0) {
425	      const globalDb = openGlobalDb(dbPath);
426	      if (globalDb) {
427	        try {
428	          const globalRow = globalDb.prepare(
429	            "SELECT value FROM cursorDiskKV WHERE key = ?"
430	          ).get(`composerData:${composerId}`) as { value: string } | undefined;
431	
432	          if (globalRow?.value) {
433	            let globalComposerData: Record<string, unknown>;
434	            try {
435	              globalComposerData = JSON.parse(globalRow.value) as Record<string, unknown>;
436	            } catch {
437	              console.warn(`[cursor] failed to parse global cursorDiskKV composerData for composer ${composerId}`);
438	              return null;
439	            }
440	            [messages, rawBubbles] = extractMessages(globalComposerData, composerId, globalDb);
441	            // Prefer composerData from global DB for richer metadata
442	            if (messages.length > 0) {
443	              composerData = globalComposerData;
444	            }
445	          }
446	        } finally {
447	          globalDb.close();
448	        }
449	      }
450	    }
451	
452	    if (messages.length === 0) return null;
453	
454	    // Resolve project path — try multiple strategies in order of reliability:
455	    //   1. workspace.json in the workspace hash directory (works for workspace DB sessions)
456	    //   2. Extract from codeBlock URIs + relevantFiles in inline composerData.conversation
457	    //   3. Extract from raw bubbles (covers fullConversationHeadersOnly where codeBlocks
458	    //      live in individual bubbleId DB rows, not inline in composerData)
459	    //   4. Fallback to cursor://workspace-<hash8> so sessions stay distinct per-workspace
460	    const wsDir = path.dirname(dbPath); // workspaceStorage/<hash>/ or globalStorage/
461	    const workspaceHash = path.basename(wsDir); // the hash directory name (or "globalStorage")
462	    const projectPath =
463	      resolveWorkspacePath(wsDir) ||
464	      extractProjectPathFromComposerData(composerData) ||
465	      extractProjectPathFromBubbles(rawBubbles) ||
466	      `cursor://workspace-${workspaceHash.slice(0, 8)}`;
467	    const projectName = projectPath.startsWith('cursor://')
468	      ? projectPath.replace('cursor://', '')
469	      : path.basename(projectPath);
470	
471	    // Build timestamps from messages
472	    const timestamps = messages.map(m => m.timestamp.getTime()).filter(t => t > 0);
473	    let startedAt = timestamps.length > 0
474	      ? new Date(timestamps.reduce((a, b) => a < b ? a : b))
475	      : new Date(0); // Epoch fallback — avoids misleading "now" timestamps
476	    let endedAt = timestamps.length > 0
477	      ? new Date(timestamps.reduce((a, b) => a > b ? a : b))
478	      : new Date(0);
479	
480	    // If timestamps are missing or invalid, try composerData timestamps
481	    const createdAt = composerData.createdAt as number | undefined;
482	    const lastUpdatedAt = (composerData.lastUpdatedAt || composerData.updatedAt) as number | undefined;
483	
484	    if (createdAt && timestamps.length === 0) {
485	      startedAt = new Date(createdAt);
486	    }
487	    if (lastUpdatedAt && lastUpdatedAt > startedAt.getTime()) {
488	      endedAt = new Date(lastUpdatedAt);
489	    }
490	
491	    const userMessages = messages.filter(m => m.type === 'user');
492	    const assistantMessages = messages.filter(m => m.type === 'assistant');
493	    const toolCallCount = messages.reduce((sum, m) => sum + m.toolCalls.length, 0);
494	
495	    // Extract gitBranch from the first user bubble that has gitStatusRaw.
496	    // gitStatusRaw looks like: "On branch master\nYour branch is up to date..."
497	    // gitStatusRaw is not surfaced on ParsedMessage — scan rawBubbles directly.
498	    let gitBranch: string | null = null;
499	    for (const bubble of rawBubbles) {
500	      if ((bubble.type === 1 || bubble.role === 'user') && typeof bubble.gitStatusRaw === 'string') {
501	        const match = bubble.gitStatusRaw.match(/^On branch (.+)/m);
502	        if (match) {
503	          const branchName = match[1].trim();
504	          // Exclude detached HEAD state which git reports as "(no branch)"
505	          if (branchName !== '(no branch)') {
506	            gitBranch = branchName;
507	          }
508	          break;
509	        }
510	      }
511	    }
512	
513	    // Build session usage from composerData.usageData (cost in cents) and
514	    // per-bubble tokenCount aggregation (inputTokens/outputTokens on assistant bubbles).
515	    let usage: import('../types.js').SessionUsage | undefined;
516	    const usageData = composerData.usageData as Record<string, { costInCents?: number }> | undefined;
517	    const costInCents = usageData?.default?.costInCents;
518	
519	    // Sum token counts from assistant bubbles (user bubbles always report 0)
520	    let totalInput = 0;
521	    let totalOutput = 0;
522	    for (const bubble of rawBubbles) {
523	      if (bubble.type === 2 || bubble.role === 'assistant') {
524	        const tc = bubble.tokenCount as Record<string, number> | undefined;
525	        if (tc) {
526	          totalInput += tc.inputTokens || 0;
527	          totalOutput += tc.outputTokens || 0;
528	        }
529	      }
530	    }
531	
532	    if (typeof costInCents === 'number' || totalInput > 0 || totalOutput > 0) {
533	      usage = {
534	        totalInputTokens: totalInput,
535	        totalOutputTokens: totalOutput,
536	        cacheCreationTokens: 0,
537	        cacheReadTokens: 0,
538	        estimatedCostUsd: typeof costInCents === 'number' ? costInCents / 100 : 0,
539	        modelsUsed: [],
540	        primaryModel: 'unknown',
541	        usageSource: 'session',
542	      };
543	    }
544	
545	    // Check if Cursor tagged this session as an agentic session.
546	    // unifiedMode === 'agent' (vs 'ask') or isAgentic === true marks agent-mode sessions.
547	    const isAgentic =
548	      composerData.unifiedMode === 'agent' ||
549	      composerData.isAgentic === true;
550	
551	    const session: ParsedSession = {
552	      id: `cursor:${composerId}`,
553	      projectPath,
554	      projectName,
555	      summary: (composerData.name as string) || null, // Cursor's conversation name/title
556	      generatedTitle: null,
557	      titleSource: null,
558	      sessionCharacter: null,
559	      startedAt,
560	      endedAt,
561	      messageCount: userMessages.length + assistantMessages.length,
562	      userMessageCount: userMessages.length,
563	      assistantMessageCount: assistantMessages.length,
564	      toolCallCount,
565	      compactCount: 0,
566	      autoCompactCount: 0,
567	      slashCommands: [],
568	      gitBranch,
569	      claudeVersion: null,
570	      sourceTool: 'cursor',
571	      usage,
572	      messages,
573	    };
574	
575	    // Generate title using existing title generator
576	    const titleResult = generateTitle(session);
577	    session.generatedTitle = titleResult.title;
578	    session.titleSource = titleResult.source;
579	
580	    // Detect session character. If detection returns null and Cursor marked the session
581	    // as agentic (unifiedMode === 'agent' / isAgentic === true), default to 'feature_build'
582	    // as the closest character for autonomous multi-step agent sessions.
583	    const detectedCharacter = titleResult.character || detectSessionCharacter(session);
584	    session.sessionCharacter = detectedCharacter ?? (isAgentic ? 'feature_build' : null);
585	
586	    return session;
587	  } catch {
588	    return null;
589	  } finally {
590	    db?.close();
591	  }
592	}
593	
594	// Keys Cursor has used across versions to store the message array.
595	// Order matters: check the most common/modern formats first.
596	const CURSOR_MESSAGE_ARRAY_KEYS = [
597	  'conversation',    // Observed in Cursor ≤0.42 cursorDiskKV entries
598	  'messages',        // Earlier workspace DB format
599	  'bubbles',         // Observed in some Cursor 0.43+ cursorDiskKV entries
600	  'turns',           // Seen in experimental Cursor builds
601	  'history',         // Alternate key used in some Cursor forks
602	  'richConversation',// Rich-text variant with full markdown blocks
603	  'thread',          // Used in agent-mode sessions
604	] as const;
605	
606	/**
607	 * Find the message array in a composerData blob, trying all known key names.
608	 * Returns [array, keyUsed] so callers can log which key worked.
609	 * Returns [[], null] when no recognised key has a non-empty array.
610	 */
611	function findMessageArray(composerData: Record<string, unknown>): [Array<Record<string, unknown>>, string | null] {
612	  for (const key of CURSOR_MESSAGE_ARRAY_KEYS) {
613	    const value = composerData[key];
614	    if (Array.isArray(value) && value.length > 0) {
615	      return [value as Array<Record<string, unknown>>, key];
616	    }
617	  }
618	  return [[], null];
619	}
620	
621	/**
622	 * Extract parsed messages from Cursor composer data.
623	 *
624	 * Handles two storage formats:
625	 * 1. Inline: composerData has a `conversation` (or `messages`, etc.) array with full bubble content.
626	 * 2. Headers-only (Cursor v3+/v6): composerData has `fullConversationHeadersOnly` with bubble IDs
627	 *    and types only. Full bubble content is stored in separate `bubbleId:<composerId>:<bubbleId>`
628	 *    rows in the same cursorDiskKV table.
629	 *
630	 * Returns [parsedMessages, rawBubbles]. rawBubbles is the unprocessed bubble array used by
631	 * extractProjectPathFromBubbles() for project path inference.
632	 */
633	function extractMessages(
634	  composerData: Record<string, unknown>,
635	  sessionId: string,
636	  db: InstanceType<typeof Database> | null,
637	): [ParsedMessage[], Array<Record<string, unknown>>] {
638	  // Strategy 1: Try fullConversationHeadersOnly (newer Cursor format, ~72% of sessions)
639	  const headers = composerData.fullConversationHeadersOnly;
640	  if (Array.isArray(headers) && headers.length > 0 && db) {
641	    const rawBubbles = loadBubblesFromHeaders(
642	      headers as Array<{ bubbleId: string; type: number }>,
643	      sessionId,
644	      db,
645	    );
646	    if (rawBubbles.length > 0) {
647	      return [parseBubbles(rawBubbles, sessionId), rawBubbles];
648	    }
649	    // If all bubble lookups failed, fall through to inline check
650	  }
651	
652	  // Strategy 2: Try inline message arrays (older Cursor format)
653	  const [rawBubbles, keyUsed] = findMessageArray(composerData);
654	
655	  if (rawBubbles.length === 0) {
656	    // No messages found — log top-level keys to help diagnose future Cursor format changes.
657	    // Only log when the composerData has keys but none match our known formats
658	    // (empty objects = legitimately empty sessions, not a format issue).
659	    const topLevelKeys = Object.keys(composerData);
660	    const knownKeys = new Set<string>([...CURSOR_MESSAGE_ARRAY_KEYS, 'fullConversationHeadersOnly']);
661	    const hasUnknownArrayKeys = topLevelKeys.some(
662	      k => !knownKeys.has(k) && Array.isArray(composerData[k])
663	    );
664	    if (topLevelKeys.length > 0 && hasUnknownArrayKeys) {
665	      if (isVerbose()) {
666	        process.stderr.write(
667	          `[code-insights] cursor: session ${sessionId} — unrecognised composerData structure. ` +
668	          `Top-level keys: [${topLevelKeys.join(', ')}]\n`
669	        );
670	      }
671	    }
672	    return [[], []];
673	  }
674	
675	  // Log which key was used when it's not the primary expected key — helps track format drift
676	  if (keyUsed && keyUsed !== 'conversation') {
677	    if (isVerbose()) {
678	      process.stderr.write(
679	        `[code-insights] cursor: session ${sessionId} — messages found under key "${keyUsed}"\n`
680	      );
681	    }
682	  }
683	
684	  return [parseBubbles(rawBubbles, sessionId), rawBubbles];
685	}
686	
687	/**
688	 * Load full bubble data from individual cursorDiskKV rows.
689	 * Each bubble is stored at key `bubbleId:<composerId>:<bubbleId>`.
690	 */
691	function loadBubblesFromHeaders(
692	  headers: Array<{ bubbleId: string; type: number }>,
693	  composerId: string,
694	  db: InstanceType<typeof Database>,
695	): Array<Record<string, unknown>> {
696	  const bubbles: Array<Record<string, unknown>> = [];
697	  const stmt = db.prepare("SELECT value FROM cursorDiskKV WHERE key = ?");
698	
699	  for (const header of headers) {
700	    if (!header.bubbleId) continue;
701	    try {
702	      const row = stmt.get(`bubbleId:${composerId}:${header.bubbleId}`) as { value: string } | undefined;
703	      if (row?.value) {
704	        const bubble = JSON.parse(row.value) as Record<string, unknown>;
705	        bubbles.push(bubble);
706	      }
707	    } catch {
708	      // Individual bubble parse failure — skip it, keep loading others
709	    }
710	  }
711	
712	  return bubbles;
713	}
714	
715	/**
716	 * Parse an array of bubble objects into ParsedMessage[].
717	 * Shared by both inline and headers-only code paths.
718	 */
719	function parseBubbles(conversation: Array<Record<string, unknown>>, sessionId: string): ParsedMessage[] {
720	  const messages: ParsedMessage[] = [];
721	
722	  for (let i = 0; i < conversation.length; i++) {
723	    const bubble = conversation[i];
724	
725	    // Determine message type
726	    let type: 'user' | 'assistant' | 'system';
727	    if (bubble.type === 1 || bubble.role === 'user') {
728	      type = 'user';
729	    } else if (bubble.type === 2 || bubble.role === 'assistant') {
730	      type = 'assistant';
731	    } else {
732	      type = 'system';
733	    }
734	
735	    // Extract content.
736	    //
737	    // Cursor stores user messages with both `text` (plain string) and `richText`
738	    // (a Lexical editor JSON tree). We prefer `text` when it exists since it's
739	    // already the plain-text equivalent. Only fall back to parsing the Lexical
740	    // JSON when `text` is absent or empty.
741	    //
742	    // Assistant messages typically only have `text` or `content`.
743	    let content: string;
744	    const textField = (bubble.text as string | undefined) || '';
745	    const contentField = (bubble.content as string | undefined) || '';
746	
747	    if (textField) {
748	      content = textField;
749	    } else if (bubble.richText) {
750	      // richText may be a Lexical JSON object (user bubbles) or a plain string (older formats).
751	      // Try Lexical extraction first; fall back to coercing whatever value we have to a string.
752	      const lexical = extractLexicalText(bubble.richText);
753	      if (lexical !== null) {
754	        content = lexical;
755	      } else {
756	        content = typeof bubble.richText === 'string'
757	          ? bubble.richText
758	          : '';
759	      }
760	    } else {
761	      content = contentField;
762	    }
763	
764	    if (!content && type !== 'system') continue; // Skip empty messages
765	
766	    // Truncate to 10,000 chars (same as Claude Code parser)
767	    const truncatedContent = content.length > 10000 ? content.slice(0, 10000) : content;
768	
769	    // Extract timestamp (milliseconds).
770	    // Cursor does not store a createdAt field on bubbles. Real wall-clock time lives
771	    // in assistant bubbles under timingInfo.clientRpcSendTime (Unix ms). User bubbles
772	    // have no timestamp — leave as epoch so session bounds code filters them out.
773	    // NOTE: clientStartTime is a performance offset (e.g. 926228.7 ms), NOT a wall clock.
774	    let timestamp: Date;
775	    const timingInfo = bubble.timingInfo as Record<string, unknown> | undefined;
776	    const clientRpcSendTime = timingInfo?.clientRpcSendTime;
777	    if (typeof clientRpcSendTime === 'number' && clientRpcSendTime > 1_000_000_000_000) {
778	      // Sanity-check: must be after 2001-09-09 (Unix ms > 1e12) to be a wall clock
779	      timestamp = new Date(clientRpcSendTime);
780	    } else {
781	      timestamp = new Date(0); // Epoch fallback — filtered out of session bounds calculation
782	    }
783	
784	    // Extract tool calls from toolFormerData if present
785	    const toolCalls: ToolCall[] = [];
786	    if (bubble.toolFormerData) {
787	      try {
788	        const toolData = typeof bubble.toolFormerData === 'string'
789	          ? JSON.parse(bubble.toolFormerData) as Record<string, unknown>
790	          : bubble.toolFormerData as Record<string, unknown>;
791	        if (toolData.name || toolData.toolName) {
792	          toolCalls.push({
793	            id: (bubble.bubbleId as string) || `tool-${i}`,
794	            name: (toolData.name || toolData.toolName || 'unknown') as string,
795	            input: (toolData.input || toolData.arguments || {}) as Record<string, unknown>,
796	          });
797	        }
798	      } catch {
799	        // Ignore malformed tool data
800	      }
801	    }
802	
803	    // Extract tool calls from codeBlocks if they look like file edits.
804	    // Cursor stores applied code edits as codeBlocks where `uri` is a VSCode URI
805	    // object (not a plain string). We use extractFilePath() to get the actual path.
806	    if (bubble.codeBlocks && Array.isArray(bubble.codeBlocks)) {
807	      for (const block of bubble.codeBlocks as Array<Record<string, unknown>>) {
808	        const filePath = extractFilePath(block.uri) || (typeof block.filePath === 'string' ? block.filePath : '');
809	        if (filePath) {
810	          toolCalls.push({
811	            id: `codeblock-${i}-${toolCalls.length}`,
812	            name: 'Edit',
813	            input: {
814	              file_path: filePath,
815	              code: ((block.code || block.content || '') as string).slice(0, 1000),
816	            },
817	          });
818	        }
819	      }
820	    }
821	
822	    messages.push({
823	      id: (bubble.bubbleId as string) || `cursor-${sessionId}-${i}`,
824	      sessionId: `cursor:${sessionId}`,
825	      type,
826	      content: truncatedContent,
827	      thinking: null, // Cursor doesn't expose thinking
828	      toolCalls,
829	      toolResults: [], // Not available from Cursor's format
830	      usage: null, // Per-message usage not available; session-level tokens aggregated from rawBubbles
831	      timestamp,
832	      parentId: null,
833	    });
834	  }
835	
836	  return messages;
837	}
